import{_ as t,o as a,c as o,a0 as s}from"./chunks/framework.DTwdCQre.js";const u=JSON.parse('{"title":"ADR-001: Agent Loop Design","description":"","frontmatter":{},"headers":[],"relativePath":"adr/001-agent-loop.md","filePath":"adr/001-agent-loop.md","lastUpdated":1775554522000}'),n={name:"adr/001-agent-loop.md"};function i(l,e,r,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="adr-001-agent-loop-design" tabindex="-1">ADR-001: Agent Loop Design <a class="header-anchor" href="#adr-001-agent-loop-design" aria-label="Permalink to &quot;ADR-001: Agent Loop Design&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Accepted</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The agent loop is the core of claude-code-Go. It determines how the AI:</p><ol><li>Receives user input</li><li>Decides which tools to use</li><li>Executes tools</li><li>Processes results</li><li>Generates responses</li></ol><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>We implemented a <strong>Stop-Reason Driven State Machine</strong> with the following states:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>UserInput → Think → ToolSelection → Execute → Observe → Respond</span></span>
<span class="line"><span>                ↑                              ↓</span></span>
<span class="line"><span>                └────────── Loopback ←─────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="state-transitions" tabindex="-1">State Transitions <a class="header-anchor" href="#state-transitions" aria-label="Permalink to &quot;State Transitions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Current State</th><th>Trigger</th><th>Next State</th></tr></thead><tbody><tr><td>UserInput</td><td>User sends message</td><td>Think</td></tr><tr><td>Think</td><td>Model generates tool_use</td><td>ToolSelection</td></tr><tr><td>Think</td><td>Model generates text</td><td>Respond</td></tr><tr><td>ToolSelection</td><td>Tool selected</td><td>Execute</td></tr><tr><td>Execute</td><td>Tool completes</td><td>Observe</td></tr><tr><td>Observe</td><td>Tool result sent to model</td><td>Think</td></tr><tr><td>Respond</td><td>Response shown</td><td>UserInput</td></tr></tbody></table><h3 id="stop-reasons" tabindex="-1">Stop Reasons <a class="header-anchor" href="#stop-reasons" aria-label="Permalink to &quot;Stop Reasons&quot;">​</a></h3><p>The model can return these stop reasons:</p><ul><li><code>end_turn</code>: Conversation complete, wait for user</li><li><code>tool_use</code>: Model wants to use a tool</li><li><code>max_tokens</code>: Context limit reached, need compaction</li><li><code>stop_sequence</code>: Special stop token encountered</li></ul><h3 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p><strong>Positive:</strong></p><ul><li>Predictable behavior</li><li>Easy to debug</li><li>Clear state tracking</li><li>Supports both single-turn and multi-turn</li></ul><p><strong>Negative:</strong></p><ul><li>Complex state management</li><li>Need to handle all edge cases</li><li>Potential for infinite loops (mitigated with max_turns)</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><ol><li><strong>Event-Driven Architecture</strong>: More flexible but harder to reason about</li><li><strong>Coroutine-Based</strong>: Could use Go channels, but added complexity</li><li><strong>Recursive Loop</strong>: Simpler but harder to track state</li></ol><h2 id="related-decisions" tabindex="-1">Related Decisions <a class="header-anchor" href="#related-decisions" aria-label="Permalink to &quot;Related Decisions&quot;">​</a></h2><ul><li>ADR-003: Context Management</li><li>ADR-005: Session Persistence</li></ul>`,23)])])}const b=t(n,[["render",i]]);export{u as __pageData,b as default};
